package il.co.dcd.composermapper.render; import il.co.dcd.composermapper.index.Indexes; import il.co.dcd.composermapper.model.JavaClassDef; import il.co.dcd.composermapper.service.LinkResolver; import il.co.dcd.composermapper.util.FileUtil; import java.nio.file.Path; import java.io.IOException; import java.util.Set;
public class JavaClassMarkdownWriter { public void write(JavaClassDef j, Indexes x, LinkResolver links, Path vault){ Path out=vault.resolve("classes").resolve(j.getFullyQualifiedName().replace('.','/')+".md"); StringBuilder sb=new StringBuilder(); sb.append("# ").append(j.getFullyQualifiedName()).append("\n\n---\nentity_type: java_class\nentity_id: ").append(j.getFullyQualifiedName()).append("\nsource_file: ").append(j.getSourceFile()).append("\nsource_hash: ").append(FileUtil.sha256(j.getSourceFile())).append("\n---\n\n## Package\n"); sb.append(MarkdownSupport.bullet(MarkdownSupport.code(j.getPackageName()))); sb.append("\n## Methods\n"); if(j.getMethodNames().isEmpty()) sb.append("- None\n"); else j.getMethodNames().forEach(m->sb.append(MarkdownSupport.bullet(MarkdownSupport.code(m)))); sb.append("\n## Setter Methods\n"); if(j.getSetterNames().isEmpty()) sb.append("- None\n"); else j.getSetterNames().forEach(m->sb.append(MarkdownSupport.bullet(MarkdownSupport.code(m)))); sb.append("\n## Imports\n"); if(j.getImports().isEmpty()) sb.append("- None\n"); else j.getImports().forEach(i->sb.append(MarkdownSupport.bullet(MarkdownSupport.code(i)))); sb.append("\n## Used By Steps\n"); Set<String> steps=x.classUsedBySteps().get(j.getFullyQualifiedName()); if(steps==null||steps.isEmpty()) sb.append("- None\n"); else steps.forEach(id->sb.append(MarkdownSupport.bullet(links.stepLink(id)))); sb.append("\n## Inferred External Dependencies\n"); if(j.getInferredExternalDependencies().isEmpty()) sb.append("- None\n"); else j.getInferredExternalDependencies().forEach(d->sb.append(MarkdownSupport.bullet(d))); try{ FileUtil.writeString(out,sb.toString()); }catch(IOException e){ throw new RuntimeException(e);} } }
